{
  args: {
    logoWidth: 130
  },
  render: function Render({
    logoWidth,
    ...rest
  }) {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const breakpoint = useBreakpoint();
    const MobileMenuContent = () => <Grid.Root>
        <CascadingMenu.Root>
          <Grid.Item sm={12} md={12}>
            <CascadingMenu.Section>
              <MegaMenu.Title>Sanofi</MegaMenu.Title>
              {sanofiMenu.map(item => renderMenuItem(item))}
            </CascadingMenu.Section>
          </Grid.Item>
          <Grid.Item sm={12} md={12}>
            <CascadingMenu.Section variant="secondary" logo={<Image src={\`\${SANOFI_ELEMENTS_CDN_URL}/brand-logos/sanofi-campus.svg\`} alt="Sanofi Logo" height="40px" />}>
              {secondMenuData.map(item => renderMenuItem(item))}
            </CascadingMenu.Section>
          </Grid.Item>
        </CascadingMenu.Root>
        <MegaMenu.QuickAction>
          <Button label="Request a representative" fullWidth inverse={rest.isBackgroundBranded} />
        </MegaMenu.QuickAction>
      </Grid.Root>;
    return <NavigationHeader.Root logo={<div className={styles.logo}>
            {!["xs", "sm"].includes(breakpoint) && <Menu>
                <Menu.Trigger>
                  <ButtonIcon icon={IconName.APPS} variant={ButtonVariant.TERTIARY_NEUTRAL} size={ButtonSize.SMALL} onClick={() => setIsMenuOpen(!isMenuOpen)} />
                </Menu.Trigger>
                <Menu.Dropdown>
                  <Menu.Item>
                    <Image src={\`\${SANOFI_ELEMENTS_CDN_URL}/brand-logos/sanofi-campus.svg\`} alt="Sanofi Logo" height="40px" />
                  </Menu.Item>

                  {secondMenuData.map(section => <Menu.SubMenu key={section.id} label={section.label} data-testid="menu-item-xxx">
                      {section.content?.sectionContent?.map(subsection => subsection.content ? <Menu.SubMenu key={subsection.id} label={subsection.label} data-testid="sub-menu-item-xxx">
                            {subsection.content?.sectionContent?.map(item => <Menu.Item key={item.id}>
                                <span>
                                  <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                    {item.label}
                                  </Typography>
                                </span>
                              </Menu.Item>)}
                          </Menu.SubMenu> : <Menu.Item key={subsection.id}>
                            <span>
                              <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                {subsection.label}
                              </Typography>
                            </span>
                          </Menu.Item>)}
                    </Menu.SubMenu>)}
                </Menu.Dropdown>
              </Menu>}

            <Image src={\`\${SANOFI_CDN_URL}/beyfortus/Beyfortus_TM_Dosage_RGB.svg\`} style={{
        width: \`\${logoWidth}px\`
      }} alt="Sanofi logo" />
          </div>} isBackgroundBranded={rest.isBackgroundBranded} mobileMenuIcon={<MegaMenu.Trigger menuContent={<MobileMenuContent />} hasActiveShadow={true} className={styles.menu}>
            <ButtonIcon icon={IconName.APPS} size={ButtonSize.SMALL} variant={ButtonVariant.TERTIARY} inverse={rest.isBackgroundBranded} />
          </MegaMenu.Trigger>} {...rest}>
        <NavigationHeader.StartContent>
          {sanofiMenu.map(arg => renderNavHeader({
          ...arg
        }))}

          <NavigationHeader.Item lg={false} xl={false} xxl={false} xxxl={false}>
            <Menu>
              <Menu.Trigger>
                <NavigationHeader.Action>
                  More <Menu.Item.Icon name={IconName.EXPAND_MORE} />
                </NavigationHeader.Action>
              </Menu.Trigger>
              <Menu.Dropdown>
                {sanofiMenu.map((section, index) => {
                if (index < 2) return null;
                return <Menu.SubMenu key={section.id} label={section.label} data-testid="menu-item-xxx">
                      {section.content?.sectionContent?.map(subsection => subsection.content ? <Menu.SubMenu key={subsection.id} label={subsection.label} data-testid="sub-menu-item-xxx">
                            {subsection.content?.sectionContent?.map(item => <Menu.Item key={item.id}>
                                <span>
                                  <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                    {item.label}
                                  </Typography>
                                </span>
                              </Menu.Item>)}
                          </Menu.SubMenu> : <Menu.Item key={subsection.id}>
                            <span>
                              <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                {subsection.label}
                              </Typography>
                            </span>
                          </Menu.Item>)}
                    </Menu.SubMenu>;
              })}
              </Menu.Dropdown>
            </Menu>
          </NavigationHeader.Item>
        </NavigationHeader.StartContent>
        <NavigationHeader.EndContent>
          <NavigationHeader.Item>
            <ButtonIcon icon={IconName.SEARCH} variant={ButtonVariant.TERTIARY} inverse={rest.isBackgroundBranded} />
          </NavigationHeader.Item>
          <NavigationHeader.Item>
            <Button label="Action" fullWidth inverse={rest.isBackgroundBranded} />
          </NavigationHeader.Item>
        </NavigationHeader.EndContent>
        <NavigationHeader.QuickAction>
          <ButtonIcon icon={IconName.SEARCH} size={ButtonSize.SMALL} inverse={!rest.isBackgroundBranded} />
        </NavigationHeader.QuickAction>
      </NavigationHeader.Root>;
  }
}
